import { Box, ReadMore, Table } from '@navikt/ds-react';
import { AvsluttOppgave } from 'src/components/Meldinger/Detail/AvsluttOppgave';
import { oppgavePrioritet, oppgaveTyper } from 'src/components/Meldinger/oppgave-utils';
import type { OppgaveDto } from 'src/generated/modiapersonoversikt-api';
import { useGsakTema, usePersonOppgaver } from 'src/lib/clients/modiapersonoversikt-api';
import { datoEllerNull } from 'src/utils/string-utils';

export const TraadOppgaver = ({ traadId }: { traadId: string }) => {
    const { data: oppgaver = [] } = usePersonOppgaver();
    const { data: gsakTema } = useGsakTema();

    const traadOppgaver = oppgaver?.filter((oppagve: OppgaveDto) => oppagve.traadId === traadId);

    if (traadOppgaver.length === 0) {
        return null;
    }

    const flertall = traadOppgaver.length > 1;

    return (
        <ReadMore header={`${traadOppgaver.length} ${flertall ? 'åpne' : 'åpen'} oppgave${flertall ? 'r' : ''}`}>
            <Box paddingInline="space-16" paddingBlock="space-8">
                <Table size="small" data-testid="oppgaver-table">
                    <Table.Header>
                        <Table.Row>
                            <Table.HeaderCell scope="col" textSize="small" />
                            <Table.HeaderCell scope="col" textSize="small">
                                Oppgave-id
                            </Table.HeaderCell>
                            <Table.HeaderCell scope="col" textSize="small">
                                Oppgavetype
                            </Table.HeaderCell>
                            <Table.HeaderCell scope="col" textSize="small">
                                Tema
                            </Table.HeaderCell>
                            <Table.HeaderCell scope="col" textSize="small">
                                Prioritering
                            </Table.HeaderCell>
                            <Table.HeaderCell scope="col" textSize="small">
                                Frist
                            </Table.HeaderCell>
                        </Table.Row>
                    </Table.Header>
                    <Table.Body>
                        {traadOppgaver.map((p) => {
                            const tema = gsakTema.find((item) => item.kode === p.tema);
                            return (
                                <Table.Row key={p.oppgaveId} shadeOnHover={false}>
                                    <Table.DataCell>
                                        <AvsluttOppgave oppgave={p} />
                                    </Table.DataCell>
                                    <Table.DataCell textSize="small">{p.oppgaveId}</Table.DataCell>
                                    <Table.DataCell textSize="small">
                                        {oppgaveTyper[p.oppgavetype as keyof typeof oppgaveTyper] ??
                                            'Ukjent oppgavetype'}
                                    </Table.DataCell>
                                    <Table.DataCell textSize="small">{tema?.tekst ?? 'Ukjent tema'}</Table.DataCell>
                                    <Table.DataCell textSize="small">
                                        {oppgavePrioritet[p.prioritet as keyof typeof oppgavePrioritet] ?? ''}
                                    </Table.DataCell>
                                    <Table.DataCell textSize="small">
                                        {datoEllerNull(p?.fristFerdigstillelse)}
                                    </Table.DataCell>
                                </Table.Row>
                            );
                        })}
                    </Table.Body>
                </Table>
            </Box>
        </ReadMore>
    );
};
